app.get("/api/executions/:id", (req, res) => {
  const { id } = req.params as { id: string };
  const record = getExecution(id);
  if (!record) { respondWithProblem(res, 404, "NotFound", "execution not found", req.originalUrl || req.url || "/api/executions"); return; }
  res.json(record);
});

